const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const FormData = (await import('form-data')).default;
    const form = new FormData();
    form.append('file', buffer, { filename: 'audio.mp4', contentType: 'video/mp4' });
    form.append('model', 'Systran/faster-whisper-small');

    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `${$env.WHISPER_URL || 'http://localhost:8000'}/v1/audio/transcriptions`,
      headers: form.getHeaders(),
      body: form,
      encoding: 'utf-8',
      json: true
    });

    results.push({
      json: {
        ...items[i].json,
        text: response.text || ''
      }
    });
  } catch (error) {
    results.push({
      json: {
        ...items[i].json,
        text: items[i].json.caption || '',
        whisperError: error.message
      }
    });
  }
}

return results;

// Normalize output from OCR and Whisper branches
const items = $input.all();
return items.map(item => {
  const json = item.json;

  // OCR path: extract ParsedText
  if (json.ParsedResults) {
    return {
      json: {
        ...json,
        extractedText: (json.ParsedResults || []).map(r => r.ParsedText).join('\n'),
        sourceType: 'ocr'
      }
    };
  }

  // Whisper path: text is already in json.text
  if (json.text) {
    return {
      json: {
        ...json,
        extractedText: json.text,
        sourceType: 'whisper'
      }
    };
  }

  // Passthrough with caption fallback
  return {
    json: {
      ...json,
      extractedText: json.caption || '',
      sourceType: 'caption'
    }
  };
});

const items = $input.all();
const results = [];

for (const item of items) {
  const json = item.json;
  const extractedText = json.extractedText || '';
  const caption = json.caption || 'N/A';

  // Call OpenRouter to extract tool names
  let tools = [];
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://openrouter.ai/api/v1/chat/completions',
      headers: {
        'Authorization': `Bearer ${$env.OPENROUTER_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: {
        model: 'anthropic/claude-sonnet-4',
        max_tokens: 500,
        temperature: 0,
        messages: [{
          role: 'user',
          content: `You are a tool extractor for Claude Code development tools.\n\nGiven the following Instagram post content, extract any Claude Code tools, plugins, skills, frameworks, or MCP servers mentioned.\n\nReturn ONLY a JSON object with this exact format:\n{"tools": ["Tool Name 1", "Tool Name 2"]}\n\nIf no tools are mentioned, return: {"tools": []}\n\nRules:\n- Extract the canonical name (e.g. "Superpowers" not "the superpowers plugin")\n- Include MCP servers, skills, plugins, frameworks, and CLI tools\n- Exclude generic terms like "Claude", "AI", "LLM" — only specific tool names\n- Do NOT include descriptions, just names\n\nContent:\n${extractedText}\n\nCaption:\n${caption}`
        }]
      },
      json: true
    });

    const responseText = response.choices?.[0]?.message?.content || '';
    const match = responseText.match(/\{[\s\S]*?\}/);
    if (match) {
      const parsed = JSON.parse(match[0]);
      tools = parsed.tools || [];
    }
  } catch (e) {
    // If API call or parsing fails, skip
  }

  if (tools.length === 0) continue;

  const sourceUrl = json.shortCode
    ? `https://www.instagram.com/p/${json.shortCode}/`
    : json.url || 'unknown';

  let postType = 'image';
  if (json.type === 'Video') postType = 'reel';
  else if (json.type === 'Sidecar') postType = 'carousel';

  results.push({
    json: {
      sourceUrl,
      postType,
      rawText: extractedText || caption,
      tools,
      creatorHandle: json.ownerUsername || ''
    }
  });
}

return results;
